import { Routes } from '@angular/router';
import { authGuard, loggedInGuard } from '../guards/auth.guard';

export const routes: Routes = [
  { path: '', loadComponent: async () => import('./home/home').then((module) => module.HomePage), canActivate: [loggedInGuard] },
  { path: 'generator', loadComponent: async () => import('./generator/generator').then((module) => module.GeneratorPage) },
  { path: 'wiki', loadComponent: async () => import('./wiki/wiki').then((module) => module.WikiPage) },
  { path: 'game', loadComponent: async () => import('./game/game').then((module) => module.GamePage), canActivate: [authGuard] },

  { path: '**', redirectTo: '' },
];
